const input = $('Workflow Trigger').first().json;
const action = input.action;
const tenantId = input.tenant_id;
const phone = input.phone;
const customerName = input.customer_name || '';
const customerId = input.customer_id || '';

const raw = $input.first().json;
let cartId = null;
let cart = { items: [], total: 0, status: 'open' };

if (raw.document) {
  cartId = raw.document.name.split('/').pop();
  const fields = raw.document.fields || {};
  cart.status = fields.status?.stringValue || 'open';
  cart.items = [];

  if (fields.items?.arrayValue?.values) {
    for (const v of fields.items.arrayValue.values) {
      if (v.mapValue?.fields) {
        const f = v.mapValue.fields;
        cart.items.push({
          sku: f.sku?.stringValue || '',
          product_name: f.product_name?.stringValue || '',
          price: Number(f.price?.doubleValue ?? f.price?.integerValue ?? 0),
          quantity: Number(f.quantity?.integerValue ?? f.quantity?.doubleValue ?? 1),
        });
      }
    }
  }
}

function calcTotal(items) {
  return Math.round(items.reduce((sum, i) => sum + (i.price * i.quantity), 0) * 100) / 100;
}

function makeOutput(actionToPersist, msg, items) {
  const finalItems = items || cart.items;
  const base = {
    success: true,
    items: finalItems,
    total: calcTotal(finalItems),
    item_count: finalItems.length,
    message: msg,
  };

  if (actionToPersist) {
    base._action = actionToPersist;
    base._cartId = cartId;
    base._tenantId = tenantId;
    base._phone = phone;
    base._customerName = customerName;
    base._customerId = customerId;
  }
  return [{ json: base }];
}

if (action === 'view') {
  if (cart.items.length === 0) {
    return [{ json: { success: true, empty: true, message: 'Carrinho vazio.', items: [], total: 0, item_count: 0 } }];
  }
  cart.total = calcTotal(cart.items);
  return [{ json: { success: true, empty: false, items: cart.items, total: cart.total, item_count: cart.items.length } }];
}

if (action === 'clear') {
  if (!cartId) return [{ json: { success: true, message: 'Carrinho já estava vazio.', items: [], total: 0, item_count: 0 } }];
  return [{ json: { _action: 'delete', _cartId: cartId, _tenantId: tenantId, success: true, message: 'Carrinho limpo.', items: [], total: 0, item_count: 0 } }];
}

if (action === 'add') {
  const sku = String(input.sku || '').trim();
  const qty = Number(input.quantity || 1);

  const newItem = {
    sku,
    product_name: String(input.product_name || '').trim(),
    price: Number(input.price || 0),
    quantity: qty,
  };

  const existIdx = cart.items.findIndex(i => i.sku === sku);
  if (existIdx >= 0) {
    // SKU é a verdade: somar quantidade e manter nome/preço já existentes
    cart.items[existIdx].quantity += newItem.quantity;
  } else {
    cart.items.push(newItem);
  }

  return makeOutput(cartId ? 'update' : 'create', `${newItem.product_name} adicionado ao carrinho.`, cart.items);
}

if (action === 'remove') {
  const sku = String(input.sku || '').trim();
  const before = cart.items.length;
  cart.items = cart.items.filter(i => i.sku !== sku);

  if (cart.items.length === before) return [{ json: { success: false, message: 'Item não encontrado no carrinho.' } }];

  if (cart.items.length === 0 && cartId) {
    return [{ json: { _action: 'delete', _cartId: cartId, _tenantId: tenantId, success: true, items: [], total: 0, item_count: 0, message: 'Item removido. Carrinho ficou vazio.' } }];
  }
  return makeOutput('update', 'Item removido.', cart.items);
}

if (action === 'update_qty') {
  const sku = String(input.sku || '').trim();
  const newQty = Number(input.quantity || 1);

  const item = cart.items.find(i => i.sku === sku);
  if (!item) return [{ json: { success: false, message: 'Item não encontrado no carrinho.' } }];

  if (newQty <= 0) {
    cart.items = cart.items.filter(i => i.sku !== sku);
  } else {
    item.quantity = newQty;
  }
  return makeOutput('update', 'Quantidade atualizada.', cart.items);
}

return [{ json: { success: false, message: 'Ação desconhecida: ' + action } }];

const data = $input.first().json;
const action = data._action;
const tenantId = data._tenantId;
const cartId = data._cartId;
const baseUrl = `https://firestore.googleapis.com/v1/projects/saas-manu-project/databases/(default)/documents/tenants/${tenantId}`;

if (action === 'delete' && cartId) {
  return [{ json: { method: 'DELETE', url: `${baseUrl}/carts/${cartId}`, body: null } }];
}

const itemsArray = (data.items || []).map(i => ({
  mapValue: {
    fields: {
      sku: { stringValue: i.sku || '' },
      product_name: { stringValue: i.product_name || '' },
      price: { doubleValue: i.price },
      quantity: { integerValue: String(i.quantity) },
    }
  }
}));

const body = {
  fields: {
    phone: { stringValue: data._phone || '' },
    customer_name: { stringValue: data._customerName || '' },
    customer_id: { stringValue: data._customerId || '' },
    items: { arrayValue: { values: itemsArray } },
    total: { doubleValue: data.total || 0 },
    status: { stringValue: 'open' },
    updated_at: { stringValue: new Date().toISOString() }
  }
};

if (action === 'create') {
  body.fields.created_at = { stringValue: new Date().toISOString() };
  return [{ json: { method: 'POST', url: `${baseUrl}/carts`, body } }];
}

if (action === 'update' && cartId) {
  const mask = 'updateMask.fieldPaths=items&updateMask.fieldPaths=total&updateMask.fieldPaths=status&updateMask.fieldPaths=updated_at';
  return [{ json: { method: 'PATCH', url: `${baseUrl}/carts/${cartId}?${mask}`, body } }];
}

return [{ json: { method: 'NONE' } }];

const prev = $('Lógica do Carrinho').first().json;
const { _action, _cartId, _tenantId, _phone, _customerName, _customerId, ...clean } = prev;
return [{ json: clean }];
